/**
 * 선택된 화물의 차량 찾기
 */
scwin.f_SearchCar = function (mode, row) {
  const wfmObj = $p.parent().wfm_wframe2.getWindow();
  const ds = mode == 'cargo' ? ds_fl : ds_flc;
  let sub_ds, sub_gr;

  // 차량종류
  switch (scwin.vehclType) {
    case 'all':
      sub_ds = wfmObj.dtl_car;
      sub_gr = wfmObj.gr_car;
      break;
    case 'blk':
      sub_ds = wfmObj.dtl_car_blk;
      sub_gr = wfmObj.gr_car_blk;
      break;
    case 'cntr':
      sub_ds = wfmObj.dtl_car_cntr;
      sub_gr = wfmObj.gr_car_cntr;
      break;
    case 'matching':
      sub_ds = wfmObj.dtl_car_matching;
      // sub_gr = wfmObj.gr_car;
      break;
    case 'mb':
      sub_ds = wfmObj.dtl_car_mb;
      sub_gr = wfmObj.gr_car_mb;
      break;
    case 'public':
      break;
  }
  const vehclNo = ds.getCellData(row, "vehclNo");
  const alloccarDd = ds.getCellData(row, "alloccarDd");
  for (let i = 0; i < sub_ds.getTotalRow(); i++) {
    const sub_vehclNo = sub_ds.getCellData(i, "vehclNo").replace(/-/g, '');
    const sub_mtvehclDd = sub_ds.getCellData(i, "mtvehclDd").replace(/-/g, '');
    if (vehclNo == sub_vehclNo && alloccarDd == sub_mtvehclDd) {
      // sub_ds.RowMark
      sub_gr.setRowBackgroundColor(i, "#fcf8e3");
      sub_gr.setRowColor(i, "black");
    }
  }
};

/**
 * ds_fl dataList
 */
scwin.ds_fl_ondataload = function () {
  if (ds_fl.getTotalRow() == 0) return;
  if (scwin.vehclType == "mb") {
    scwin.selectedvehclRow = "";
    scwin.ez110Idx = ""; // wfm_wframe2에서 전달해주는 차량등록번호
  }
  const {
    idx,
    wt,
    onDt,
    dmCoshippingNo
  } = ds_fl.getRowJSON(0);
  scwin.showmb(idx, wt, onDt);

  // as-is RowMark 대응    
  // 합적번호
  if ($c.util.isEmpty($p, dmCoshippingNo)) {
    // 선택한것처럼 보이게 
    gr_fl.setRowBackgroundColor(0, "#fcf8e3");
    gr_fl.setRowColor(0, "black");
  } else {
    // 동일 합적번호 focus 처리
    const matchArr = ds_fl.getMatchedIndex("dmCoshippingNo", dmCoshippingNo, true);
    for (let i = 0; i < matchArr.length; i++) {
      gr_fl.setRowBackgroundColor(matchArr[i], "#fcf8e3");
      gr_fl.setRowColor(matchArr[i], "black");
    }
  }
  let iTotalRows = 0;
  for (let i = 0; i < ds_fl.getTotalRow(); i++) {
    let coshippingFlag = false;
    if (ds_fl.getCellData(i, "dmCoshippingNo") != "") {
      for (let j = 0; j < ds_fl.getTotalRow(); j++) {
        if (i != j && ds_fl.getCellData(i, "dmCoshippingNo") == ds_fl.getCellData(j, "dmCoshippingNo")) {
          coshippingFlag = true;
          break;
        }
      }
      if (!coshippingFlag) iTotalRows = iTotalRows + 1;
    } else {
      iTotalRows = iTotalRows + 1;
    }
  }
  tbx_totalCargo.setValue(iTotalRows);
  scwin.f_SearchCar('cargo', 0);
};

